#include <stdio.h>
#include <stdlib.h>

int n, m, g, k;
int *U, *V; // edges
char *removed;

int dfs(int rem) {
    if (rem < 0) return 0;
    int i;
    for (i = 0; i < m; ++i) {
        if (!removed[U[i]] && !removed[V[i]]) break; // uncovered edge
    }
    if (i == m) return 1; // all edges covered
    int u = U[i], v = V[i];
    // branch u
    removed[u] = 1;
    if (dfs(rem - 1)) return 1;
    removed[u] = 0;
    // branch v
    removed[v] = 1;
    if (dfs(rem - 1)) return 1;
    removed[v] = 0;
    return 0;
}

int main(){
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        if (scanf("%d %d %d", &n, &m, &g)!=3) return 0;
        k = n - g;
        U = (int*)malloc(m * sizeof(int));
        V = (int*)malloc(m * sizeof(int));
        for (int i=0;i<m;++i) scanf("%d %d", &U[i], &V[i]);
        removed = (char*)calloc(n, sizeof(char));
        int ok = dfs(k);
        printf(ok ? "Possible\n" : "Impossible\n");
        free(U); free(V); free(removed);
    }
    return 0;
}

