#include <bits/stdc++.h>
using namespace std;

int n,m,g,k;
vector<pair<int,int>> edges;
vector<char> removed;

bool dfs(int rem){
    if(rem<0) return false;
    int idx=-1;
    for(int i=0;i<m;++i){
        auto [u,v]=edges[i];
        if(!removed[u] && !removed[v]){ idx=i; break; }
    }
    if(idx==-1) return true; // all covered
    int u=edges[idx].first, v=edges[idx].second;
    removed[u]=1;
    if(dfs(rem-1)) return true;
    removed[u]=0;
    removed[v]=1;
    if(dfs(rem-1)) return true;
    removed[v]=0;
    return false;
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        cin>>n>>m>>g;
        k=n-g;
        edges.resize(m);
        for(int i=0;i<m;++i){
            int a,b;cin>>a>>b;edges[i]={a,b};
        }
        removed.assign(n,0);
        bool ok=dfs(k);
        cout<<(ok?"Possible":"Impossible")<<'\n';
    }
    return 0;
}

