#!/usr/bin/env python3
import sys
sys.setrecursionlimit(10000)

def solve_one(n,m,g,edges):
    k = n - g
    removed = [False]*n
    def dfs(rem):
        if rem < 0:
            return False
        # find uncovered edge
        for u,v in edges:
            if not removed[u] and not removed[v]:
                break
        else:
            return True
        # branch on u
        removed[u] = True
        if dfs(rem-1):
            return True
        removed[u] = False
        # branch on v
        removed[v] = True
        if dfs(rem-1):
            return True
        removed[v] = False
        return False
    return dfs(k)

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        n = int(next(it)); m = int(next(it)); g = int(next(it))
        edges = [(int(next(it)), int(next(it))) for __ in range(m)]
        out.append('Possible' if solve_one(n,m,g,edges) else 'Impossible')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

